const body = $input.first().json.body;
const signals = body.signals || [];
const summary = body.summary || {};
const fileStats = body.file_stats || {};
const analyzedAt = body.analyzed_at || new Date().toISOString();
const reportEmail = body.report_email || '';

const highRisk = signals.filter(s => s.local_risk_level === 'high');
const mediumRisk = signals.filter(s => s.local_risk_level === 'medium');
const allAtRisk = [...highRisk, ...mediumRisk];

const top50 = [...highRisk]
  .sort((a, b) => b.base_churn_score - a.base_churn_score)
  .slice(0, 50);

const analysisId = 'alegra-' + Date.now();

return [{
  json: {
    signals,
    summary,
    fileStats,
    analyzedAt,
    reportEmail,
    highRisk,
    mediumRisk,
    allAtRisk,
    top50ForLlm: top50,
    analysisId
  }
}];

