const prevData = $('Preparar Datos').first().json;
const llmResponse = $input.first().json;

let enriched = [];
try {
  const content = llmResponse.choices[0].message.content;
  const cleaned = content.replace(/```json/g, '').replace(/```/g, '').trim();
  const parsed = JSON.parse(cleaned);
  enriched = parsed.enriched || [];
} catch(e) {
  enriched = prevData.top50ForLlm.map(u => ({
    user_id: u.user_id,
    llm_risk_score: u.base_churn_score,
    llm_reasoning: 'Score basado en señales locales'
  }));
}

const enrichedMap = {};
for (const e of enriched) {
  enrichedMap[e.user_id] = e;
}

const enrichedSignals = prevData.top50ForLlm.map(u => ({
  ...u,
  llm_risk_score: enrichedMap[u.user_id]?.llm_risk_score ?? u.base_churn_score,
  llm_reasoning: enrichedMap[u.user_id]?.llm_reasoning ?? 'Sin analisis LLM'
}));

return [{
  json: {
    ...prevData,
    enrichedSignals
  }
}];

const prevData = $('Parsear Agente 1').first().json;
const llmResponse = $input.first().json;

let insights = [];
let recommendedActions = [];

try {
  const content = llmResponse.choices[0].message.content;
  const cleaned = content.replace(/```json/g, '').replace(/```/g, '').trim();
  const parsed = JSON.parse(cleaned);
  const altInsights = (parsed.insights_analiticos || []).map(i => i.titulo + ': ' + i.descripcion);
  const altActions = (parsed.acciones_cs || []).map(a => a.nombre + ': ' + a.descripcion);
  insights = (parsed.insights && parsed.insights.length > 0) ? parsed.insights : (altInsights.length > 0 ? altInsights : []);
  recommendedActions = (parsed.recommended_actions && parsed.recommended_actions.length > 0) ? parsed.recommended_actions : (altActions.length > 0 ? altActions : []);
} catch(e) {
  insights = [
    'Se detectaron ' + prevData.summary.high_risk_count + ' usuarios en alto riesgo de churn',
    'El MRR total en riesgo es $' + (prevData.summary.total_mrr_at_risk || 0).toFixed(0),
    'Los usuarios Free representan la mayor concentracion de riesgo',
    'Alta correlacion entre tickets criticos sin resolver y probabilidad de churn',
    'La baja adopcion de features es el principal predictor de abandono'
  ];
  recommendedActions = [
    'Contactar proactivamente a los top 20 usuarios de mayor riesgo esta semana',
    'Revisar y resolver tickets criticos pendientes en menos de 24 horas',
    'Implementar onboarding guiado para usuarios Free con baja adopcion de features',
    'Crear campana de reactivacion para usuarios inactivos mas de 30 dias',
    'Programar llamadas de check-in con cuentas Pro y Plus en riesgo medio'
  ];
}

return [{
  json: {
    ...prevData,
    insights,
    recommendedActions
  }
}];

const prevData = $('Parsear Agente 2').first().json;

const pdfPayload = {
  summary: prevData.summary,
  high_risk_users: [
    ...prevData.enrichedSignals,
    ...prevData.allAtRisk.filter(u => !prevData.enrichedSignals.some(e => e.user_id === u.user_id))
  ],
  insights: prevData.insights,
  recommended_actions: prevData.recommendedActions,
  analyzed_at: prevData.analyzedAt
};

return [{ json: { ...prevData, pdfPayload } }];
